---阵型格子数据，阵型的界面相关
---战斗位置坐标
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LFormationGrid:LxNodeBase
local LFormationGrid = LxClass("LFormationGrid", LxNodeBase)
------------------------------------------------------------------
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)

-----------------------------------------------------------------
function LFormationGrid:LFormationGrid()
	self._gridCount = LCombatFormationConst.GRID_MAX
	self._figureCount = LCombatFormationConst.FIGURE_MAX
	self._bShowGrid = false
	self._bShowFigureB = true
end
-----------------------------------------------------------------
function LFormationGrid:InitFormationGrid(rootTrans,isBattleShow)
	self._formationRoot = rootTrans
	self._bShowGrid = false
	self._isBattleShow = isBattleShow
	self:InitTeamPosData()
	self:InitTeamFigureData()
end
-----------------------------------------------------------------

-----------------------------------------------------------------
function LFormationGrid:InitTeamPosData()
	local layerGrid = self._formationRoot
	self._mapCorePoint = CS.FindTrans(layerGrid, "mapCore").position

	local formationParentTransA = CS.FindTrans(layerGrid, "TeamA")
	local formationParentTransB = CS.FindTrans(layerGrid, "TeamB")

	--- 阵容A里的中心位置
	local CenterAPos = CS.FindTrans(formationParentTransA,"CenterAPos")
	--- 阵容B里的中心位置
	local CenterBPos = CS.FindTrans(formationParentTransB,"CenterBPos")

	---格子必须按照顺序放九个
	local childCount = self._gridCount
	local formationGridA = {}
	local formationGridBgA = {}
	for i = 1, childCount do
		local trans = CS.FindTrans(formationParentTransA, "PosA"..i)
		if trans then
			formationGridA[i] = trans.position

			local NoStandPos = CS.FindTrans(trans,"NoStandPos")
			CS.ShowObject(NoStandPos,false)
			formationGridBgA[i] = NoStandPos
		end
	end

	local formationGridB = {}
	local formationGridBgB = {}
	for i = 1, childCount do
		local trans = CS.FindTrans(formationParentTransB, "PosB"..i)
		if trans then
			formationGridB[i] = trans.position

			local NoStandPos = CS.FindTrans(trans,"NoStandPos")
			CS.ShowObject(NoStandPos,false)
			formationGridBgB[i] = NoStandPos
		end
	end

	self._CenterAPos = CenterAPos
	self._CenterBPos = CenterBPos

	self._mapFormationGridA = formationGridA
	self._mapFormationGridB = formationGridB

	self._mapFormationGridBgA = formationGridBgA
	self._mapFormationGridBgB = formationGridBgB
end

function LFormationGrid:GetTeamPosData()
	return self._mapFormationGridA, self._mapFormationGridB, self._mapCorePoint
end

-----------------------------------------------------------------
function LFormationGrid:SetFigureTransType(type)
	local trType = type and type or 1
	self._figureTransType = trType
	local showType1 = trType == 1
	local showType2 = trType == 2
	CS.ShowObject(self._figureATrans,showType1)
	CS.ShowObject(self._figureBTrans,showType1)
	CS.ShowObject(self._figure2ATrans,showType2)
	CS.ShowObject(self._figure2BTrans,showType2)
end

function LFormationGrid:InitTeamFigureData()
	local layerGrid = self._formationRoot
	local figureATrans = CS.FindTrans(layerGrid,"FigureA")
	local figureBTrans = CS.FindTrans(layerGrid,"FigureB")
	self._figureATransDataList,self._figureBTransDataList = self:SetTransDataList(figureATrans,figureBTrans)
	self._figureATrans = figureATrans
	self._figureBTrans = figureBTrans

	local figure2ATrans = CS.FindTrans(layerGrid,"Figure2A")
	local figure2BTrans = CS.FindTrans(layerGrid,"Figure2B")

	self._figure2ATransDataList,self._figure2BTransDataList = self:SetTransDataList(figure2ATrans,figure2BTrans)
	self._figure2ATrans = figure2ATrans
	self._figure2BTrans = figure2BTrans
end

function LFormationGrid:SetTransDataList(figureATrans,figureBTrans)
	local figureCount = self._figureCount

	local figureATransDataList = {}
	local figureBTransDataList = {}
	for i = 1, figureCount do
		local trans = CS.FindTrans(figureATrans, "FigureA" .. i)
		if trans then
			figureATransDataList[i] = self:MakeFigureTransData(trans)
		end
	end

	for i = 1, figureCount do
		local trans = CS.FindTrans(figureBTrans, "FigureB" .. i)
		if trans then
			figureBTransDataList[i] = self:MakeFigureTransData(trans)
		end
	end
	return figureATransDataList,figureBTransDataList
end

function LFormationGrid:MakeFigureTransData(trans)
	local bottomTrans = CS.FindTrans(trans, "Bottom")
	local lightTrans = CS.FindTrans(bottomTrans, "Light")
	local qualityTrans = CS.FindTrans(bottomTrans, "Quality")
	local qualitySpriteTrans = CS.FindTrans(qualityTrans, "QualitySprite")
	local qualitySpriteRender = qualitySpriteTrans:GetComponent(typeSpriteRenderer)
	local indexTrans = CS.FindTrans(bottomTrans, "Index")
	local addSprite = CS.FindTrans(indexTrans, "AddSprite")
	local initQualityTrans = CS.FindTrans(bottomTrans, "InitQuality")
	return {
		root = trans,
		bottomTrans = bottomTrans,
		lightTrans = lightTrans,
		indexTrans = indexTrans,
		qualityTrans = qualityTrans,
		initQualityTrans = initQualityTrans,
		qualitySpriteRender = qualitySpriteRender,
		addSprite = addSprite,
	}
end

------------------------------------------------------------------
function LFormationGrid:GetFigureTransDataList(isRight)
	local trType = self._figureTransType or 1
	if trType == 1 then
		return isRight and self._figureBTransDataList or self._figureATransDataList
	else
		return isRight and self._figure2BTransDataList or self._figure2ATransDataList
	end
end

function LFormationGrid:GetFormationGrid(isRight)
	return isRight and self._mapFormationGridB or self._mapFormationGridA
end

function LFormationGrid:GetFigureRoot(index, isRight)
	local figureTransDataList = self:GetFigureTransDataList(isRight)
	local data = figureTransDataList[index]
	return data.root
end

function LFormationGrid:GetGridPos(pos, isRight)
	local gridData = self:GetFormationGrid(isRight)
	return gridData[pos] or Vector3.zero
end

-----------------------------------------------------------------
--设置阵型位置
function LFormationGrid:RefreshMatrix(matrix, isRight)
	local figureTransDataList = self:GetFigureTransDataList(isRight)
	local formationGridData = self:GetFormationGrid(isRight)

	for i, v in pairs(figureTransDataList) do
		local trans = v.root
		CS.ShowObject(trans,false)
	end
	for i,pos in ipairs(matrix) do
		local data = figureTransDataList[i]
		if data then
			local transPos = formationGridData[pos] or Vector3.zero
			local x = transPos.x
			local y = transPos.y
			local z = y
			local trans = data.root
			CS.ShowObject(trans,true)
			trans.position = Vector3(x, y, z)
		end
	end
end

function LFormationGrid:RefreshShowFormationGridBg(matrix,isRight)
	local formationGridBgs = isRight and self._mapFormationGridBgB or self._mapFormationGridBgA
	local canUpHeroPos = {}
	for i,pos in ipairs(matrix) do
		canUpHeroPos[pos] = true
	end
	for i,trans in ipairs(formationGridBgs) do
		CS.ShowObject(trans,canUpHeroPos[i] == nil)
	end
end

--重置初始显示
function LFormationGrid:ResetAllFigureShow()
	self:OnResetFigureShow(self:GetFigureTransDataList(true))
	self:OnResetFigureShow(self:GetFigureTransDataList(false))
end

function LFormationGrid:OnResetFigureShow(figureList)
	local trType = self._figureTransType or 1
	for k,v in pairs(figureList) do
		CS.ShowObject(v.indexTrans, true)
		CS.ShowObject(v.lightTrans, false)
		CS.ShowObject(v.qualityTrans,false or trType == 2)
	end
end

function LFormationGrid:ResetLeftTypeTwo()
	local figureList = self._figure2ATransDataList
	self:OnResetFigureShow(figureList)
end

function LFormationGrid:ResetFigureShow(isRight)
	self:OnResetFigureShow(isRight and self._figureBTransDataList or self._figureATransDataList)
end

--设置底座灯光
function LFormationGrid:SetBottomLight(pos, isShow, isRight)
	local dataList = self:GetFigureTransDataList(isRight)
	local data = dataList[pos]
	if not data then return end

	local light = data.lightTrans
	CS.ShowObject(light,isShow)
end

--显示底部品质框
function LFormationGrid:ShowBottomShadow(pos, imgPath, isRight)
	local dataList = self:GetFigureTransDataList(isRight)
	local data = dataList[pos]
	if not data then return end

	local qualityTrans = data.qualityTrans
	local indexTrans = data.indexTrans
	CS.ShowObject(qualityTrans,true)
	CS.ShowObject(indexTrans, false)

	local spriteRenderer = data.qualitySpriteRender
	self:SetImageImage(spriteRenderer, imgPath)
end

--隐藏底部品质框
function LFormationGrid:HideBottomShadow(pos,isRight)
	local trType = self._figureTransType or 1
	local dataList = self:GetFigureTransDataList(isRight)
	local data = dataList[pos]
	if not data then return end

	local qualityTrans = data.qualityTrans
	local indexTrans = data.indexTrans
	CS.ShowObject(qualityTrans,trType == 2)
	CS.ShowObject(indexTrans,true)
end

function LFormationGrid:ShowGrid(bShow)
	if self._bShowGrid == bShow then return end

	self._bShowGrid = bShow
	CS.ShowObject(self._formationRoot , bShow)
end

function LFormationGrid:ShowFigureB(bShow)
	if self._bShowFigureB == bShow then return end

	self._bShowFigureB = bShow
	local trType = self._figureTransType or 1
	CS.ShowObject(self._figureBTrans, bShow and trType == 1)
	CS.ShowObject(self._figure2BTrans, bShow and trType == 2)
end

-----------------------------------------------------------------
---@return Vector3 返回阵容A的中心位置
function LFormationGrid:GetCenterAPosition()
	return self._CenterAPos.position
end

---@return Vector3 返回阵容B的中心位置
function LFormationGrid:GetCenterBPosition()
	return self._CenterBPos.position
end

-----------------------------------------------------------------
function LFormationGrid:Destroy()
	if self._isDestroy then return end
	
	local dataList = self._figureATransDataList
	if dataList then
		for k,v in pairs(dataList) do
			dataList[k] = nil
			table.removeall(v)
		end
	end
	dataList = self._figureBTransDataList
	if dataList then
		for k,v in pairs(dataList) do
			dataList[k] = nil
			table.removeall(v)
		end
	end
	self._figureATransDataList = nil
	self._figureBTransDataList = nil
	LxNodeBase.Dispose(self)
	self._isDestroy = true
end
-----------------------------------------------------------------

return LFormationGrid